`,i.jsx(T,{direction:"DOWN",label:"Queue",title:"The in-process worker claims a job, dispatches it, and maps the reply to Done, Retry, or Failed",nodes:[{id:"worker",title:"QueueWorker",sub:["Semaphore · concurrency 128","tokio (napi edge)"]},{id:"claim",title:"claim_next",sub:["atomic UPDATE · attempts+1","15s lease reclaims abandoned"]},{id:"dispatch",title:"NapiDispatch → JS dispatcher",sub:["ThreadsafeFunction · prefix → handler","__wkf_step_ · __wkf_workflow_","ActivityGuard ++active"]},{id:"done",kind:"success",title:"Done",sub:"complete_job (delete the row)"},{id:"retry",kind:"warn",title:"Retry { delay }",sub:"fail_job(delay) · wait, then re-run"},{id:"failed",kind:"error",title:"Failed",sub:"exp-backoff · base 1s → cap 300s"},{id:"dead",kind:"error",title:"dead-letter",sub:"attempts ≥ 25 → stop, log and drop"}],edges:[{from:"worker",to:"claim",kind:"info"},{from:"claim",to:"dispatch",kind:"info"},{from:"dispatch",to:"done",kind:"success",label:"Done"},{from:"dispatch",to:"retry",kind:"warn",label:"Retry"},{from:"dispatch",to:"failed",kind:"error",label:"Failed"},{from:"retry",to:"claim",kind:"warn",dashed:!0,label:"re-enqueue"},{from:"failed",to:"dead",kind:"error",dashed:!0,label:"25 attempts"}]}),`
`,i.jsxs(n.p,{children:["A workflow or step enqueues via ",i.jsx(n.code,{children:"world.queue(name, msg, opts)"}),", which inserts into ",i.jsx(n.code,{children:"world_jobs"})," with ",i.jsx(n.code,{children:"kind"})," derived from the queue-name prefix (",i.jsx(n.code,{children:"__wkf_step_"})," = step, ",i.jsx(n.code,{children:"__wkf_workflow_"})," = flow). The worker loops: it takes a ",i.jsx(n.code,{children:"Semaphore"})," permit, calls ",i.jsx(n.code,{children:"claim_next"})," (an atomic ",i.jsx(n.code,{children:"UPDATE ... RETURNING"})," that bumps ",i.jsx(n.code,{children:"attempts"})," and reclaims any job whose 15-second lease has expired), then dispatches through ",i.jsx(n.code,{children:"NapiDispatch"})," to the JS dispatcher ",i.jsx(n.code,{children:"ThreadsafeFunction"}),". The dispatcher matches the prefix to a registered handler, runs it, and the reply maps to a ",i.jsx(n.code,{children:"DispatchOutcome"}),": ",i.jsx(n.code,{children:"Done"})," deletes the job (",i.jsx(n.code,{children:"complete_job"}),"), ",i.jsx(n.code,{children:"Retry { delay }"})," reschedules it, and ",i.jsx(n.code,{children:"Failed"})," applies exponential backoff (base 1s, capped at 300s) or dead-letters after 25 attempts. While a handler runs, an ",i.jsx(n.code,{children:"ActivityGuard"})," increments the control server's active counter so the supervisor sees the app as busy."]}),`
